// LoadUserFollowing performs the eager-load for the "following" edge. Body mirrors
// the pre-PR6 *UserQuery.loadFollowing method, hoisted to root
// so it can reference cross-package types directly.
func LoadUserFollowing(ctx context.Context, query *user.UserQuery, nodes []*user.User) error {
	edgeIDs := make([]driver.Value, len(nodes))
	byID := make(map[string]*user.User)
	nids := make(map[string]map[*user.User]struct{})
	for i, node := range nodes {
		edgeIDs[i] = node.ID
		byID[node.ID] = node
		node.Edges.Following = []*user.User{}
	}
	query.Where(func(s *sql.Selector) {
		joinT := sql.Table(user.FollowingTable)
		s.Join(joinT).On(s.C(user.FieldID), joinT.C(user.FollowingPrimaryKey[1]))
		s.Where(sql.InValues(joinT.C(user.FollowingPrimaryKey[0]), edgeIDs...))
		columns := s.SelectedColumns()
		s.Select(joinT.C(user.FollowingPrimaryKey[0]))
		s.AppendSelect(columns...)
		s.SetDistinct(false)
	})
	if err := query.PrepareQuery(ctx); err != nil {
		return err
	}
	qr := QuerierFunc(func(ctx context.Context, q Query) (Value, error) {
		return query.Fetch(ctx, func(_ context.Context, _qs *sqlgraph.QuerySpec) {
			assign := _qs.Assign
			values := _qs.ScanValues
			_qs.ScanValues = func(columns []string) ([]any, error) {
				values, err := values(columns[1:])
				if err != nil {
					return nil, err
				}
				return append([]any{new(sql.NullInt64)}, values...), nil
			}
			_qs.Assign = func(columns []string, values []any) error {
				outValue := values[0].(*sql.NullInt64).String
				inValue := values[1].(*sql.NullInt64).String
				if nids[inValue] == nil {
					nids[inValue] = map[*user.User]struct{}{byID[outValue]: {}}
					return assign(columns[1:], values[1:])
				}
				nids[inValue][byID[outValue]] = struct{}{}
				return nil
			}
		})
	})
	neighbors, err := withInterceptors[[]*user.User](ctx, query, qr, query.QueryState.Inters)
	if err != nil {
		return err
	}
	for _, n := range neighbors {
		parents, ok := nids[n.ID]
		if !ok {
			return fmt.Errorf(`unexpected "following" node returned %v`, n.ID)
		}
		for kn := range parents {
			kn.Edges.Following = append(kn.Edges.Following, n)
		}
	}
	for _, loader := range query.EagerLoaders() {
		if err := loader(ctx, neighbors); err != nil {
			return err
		}
	}
	return nil
}

